('Demera Ethiopian Restaurant','Restaurant','4801 N Broadway St','Chicago','IL','(773)-334-8787','https://www.demerachicago.com/','At Demera Ethiopian Restaurant, the spirit of Ethiopia comes alive through vibrant flavors, communal dining, and cultural authenticity. Founded by Chef Tigist Reda, a proud Black woman entrepreneur, Demera has become one of the most celebrated Ethiopian restaurants in the region. Located in the heart of Philadelphia, this culinary gem is beloved for its traditional injera platters, rich stews, and warm hospitality. Chef Reda’s deep commitment to her heritage and her community has garnered local acclaim, making Demera a standout destination for those seeking both comfort and culture on the plate.','https://blackhotelguide.com/wp-content/uploads/2020/01/3-color-268-png-vr-1.png'),
('Pier 31 Restaurant, Chicago','Restaurant','3101 S DuSable Lake Shore Dr','Chicago','IL','','','This seasonal black-owned restaurant in Chicago is nestled along the scenic shores of Lake Michigan, offering no-frills food, refreshing drinks, and unbeatable waterfront views.','https://blackhotelguide.com/wp-content/uploads/2020/01/3-color-268-png-vr-1.png'),
('Virtue Restaurant & Bar','Restaurant','1462 E 53rd St','Chicago','IL','N/A','https://www.virtuerestaurant.com/','Located in Chicago’s Hyde Park, Virtue Restaurant & Bar is a celebrated dining destination that masterfully blends Southern flavors with modern culinary artistry. Founded by African American Chef Erick Williams, a James Beard Award-winning chef, this restaurant is dedicated to serving soulful comfort food with a refined approach.','https://blackhotelguide.com/wp-content/uploads/2025/03/Virtue-Restaurant-Bar.jpg'),
('Greenleaf – Milford, NH','Restaurant','54 Nashua St','Milford','NH','(603) 213-5447','https://www.greenleafmilford.com/','Greenleaf, nestled in a beautifully restored historic bank building in downtown Milford, New Hampshire, is a Black-owned, award-winning farm-to-table restaurant helmed by Chef Chris Viaud. The restaurant offers an immersive dining experience that celebrates the bounty of New England’s seasons with a focus on sustainability and community engagement.','https://i0.wp.com/blackhotelguide.com/wp-content/uploads/2025/05/Greenleaf-%E2%80%93-Milford-NH.jpg?fit=1000%2C1000&ssl=1'),
('North of Bourbon','Restaurant','935 Goss Ave','Louisville','KY','(502) 749-3305','https://www.northofbourbon.com/','Black-owned culinary destination that fuses Kentucky bourbon culture with the rich flavors of New Orleans. Offers an immersive experience that honors Black Southern culinary traditions while embracing innovation.','https://i0.wp.com/blackhotelguide.com/wp-content/uploads/2025/05/North-of-Bourbon-Restaurant-Louisville-KY.jpg?fit=1000%2C1333&ssl=1'),
('Bridgetown Roti, Restaurant, CA','Restaurant','858 N Vermont Ave','Los Angeles','CA','','https://www.bridgetownroti.com/','Bridgetown Roti, a black-women owned restaurant located in East Hollywood, is the culinary brainchild of Chef Rashida Holmes, a James Beard Award semifinalist celebrated for her innovative approach to Caribbean cuisine. The restaurant draws inspiration from her Bajan heritage and offers signature paratha-style rotis with fillings like Mom’s chicken curry and curried shrimp, and more. It provides an immersive experience that honors Black Southern culinary traditions.','https://i0.wp.com/blackhotelguide.com/wp-content/uploads/2025/05/Bridgetown-Roti-Restaurant-CA-8.jpg?fit=666%2C1000&ssl=1')
)
INSERT INTO public.businesses (name, business_name, category, address, city, state, phone, website, description, banner_url, owner_id, listing_status, is_verified)
SELECT s.business_name, s.business_name, s.category, NULLIF(s.address,''), NULLIF(s.city,''), NULLIF(s.state,''), NULLIF(s.phone,''), NULLIF(s.website,''), NULLIF(s.description,''), NULLIF(s.banner_url,''), 'bd72a75e-1310-4f40-9c74-380443b09d9b'::uuid, 'live', true
FROM src s
WHERE NOT EXISTS (SELECT 1 FROM public.businesses b WHERE lower(regexp_replace(b.business_name,'[^A-Za-z0-9]+','','g')) = lower(regexp_replace(s.business_name,'[^A-Za-z0-9]+','','g')));